#include <stdio.h>

void swapArithmetic(int *a, int *b) {
    *a = *a + *b;
    *b = *a - *b;
    *a = *a - *b;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        swapArithmetic(&a, &b);
        printf("%d %d\n", b, a);
    }
    return 0;
}

